      d="M151.627 150.971L160.2 158.318H171.155L180.255 147.141L171.155 147.907V141.632H182.811L194.338 155.254H196.175L200.18 147.446L201.998 148.064V149.975L209.585 149.283L211.643 147.907H219.007L223.428 143.164L226.824 145.305L226.031 158.318L231.54 164.289H242.089L245.762 168.119L246.547 174.395H237.825L237.973 172.863L241.185 171.94V168.885L236.017 169.337L234.955 171.488L236.017 178.215V182.285H239.524V186.337L234.955 189.853L237.945 195.28L234.955 197.061L222.145 191.358L210.84 192.659L200.18 207.896L193.434 202.109H180.91L174.847 198.455H158.53L145.628 193.462L147.529 180.237L160.422 174.552L150.178 163.892L146.384 151.027L152.263 145.711L151.627 150.971Z"
      stroke="black"
      fill="currentColor"
      stroke-width="0.5"
    >
      <title>{{ getName(1735209) }}</title>
    </path>
  </svg>
</template>

<script setup>
import { ref, watch, defineProps, defineEmits } from "vue";
import { useI18n } from "vue-i18n";

const { locale } = useI18n();

const props = defineProps({
  data: {
    type: Array,
    required: true,
  },
  active: {
    type: [String, Number],
    default: null,
  },
});
const emit = defineEmits(["changeDistrict"]);

const hoveredRegion = ref(null);

const getName = (id) => {
  // 1. Qoraqalpog'iston tumanlarining nomlari
  const districtNames = {
    1735215: { uz: "Qo'ng'irot tumani", ru: "Кунградский район", en: "Kungrad District" },
    1735222: { uz: "Mo'ynoq tumani", ru: "Муйнакский район", en: "Muynak District" },
    1735230: { uz: "Taxtako'pir tumani", ru: "Тахтакупырский район", en: "Takhtakupyr District" },
    1735233: { uz: "To'rtko'l tumani", ru: "Турткульский район", en: "Turtkul District" },
    1735250: { uz: "Ellikkala tumani", ru: "Элликкалинский район", en: "Ellikqala District" },
    1735207: { uz: "Beruniy tumani", ru: "Берунийский район", en: "Beruniy District" },
    1735204: { uz: "Amudaryo tumani", ru: "Амударьинский район", en: "Amudarya District" },
    1735243: { uz: "Shumanay tumani", ru: "Шуманайский район", en: "Shumanay District" },
    1735236: { uz: "Xo'jayli tumani", ru: "Ходжейлийский район", en: "Khojayli District" },
    1735218: { uz: "Qanliko'l tumani", ru: "Канлыкульский район", en: "Qanlykol District" },
    1735228: { uz: "Taxiatosh tumani", ru: "Тахиаташский район", en: "Takhiatash District" },
    1735225: { uz: "Nukus tumani", ru: "Нукусский район", en: "Nukus District" },
    1735211: { uz: "Qorao'zak tumani", ru: "Караузякский район", en: "Karauzak District" },
    1735240: { uz: "Chimboy tumani", ru: "Чимбайский район", en: "Chimbay District" },
    1735212: { uz: "Kegeyli tumani", ru: "Кегейлийский район", en: "Kegeyli District" },
    1735209: { uz: "Bo'zatov tumani", ru: "Бозатауский район", en: "Bozatau District" }
  };

  // 2. API dan kelgan ma'lumotni tekshirish
  const district = props.data.find((district) => district.id == id);
  
  if (district) {
    // API dan nom kelgan bo'lsa
    if (district.district_name && district.district_name[locale.value]) {
      return district.district_name[locale.value];
    }
    // Yoki boshqa nom field'lari
    if (district.name && typeof district.name === 'object') {
      return district.name[locale.value];
    }
    if (district.name && typeof district.name === 'string') {
      return district.name;
    }
  }

  // 3. Qo'lda belgilangan nomlardan olish
  if (districtNames[id] && districtNames[id][locale.value]) {
    return districtNames[id][locale.value];
  }

  // 4. Fallback
  return `Tuman ${id}`;
};

const getPathStyle = (id) => {
  const district = props.data.find((district) => district.id == id);

  let className = "";

  if (district) {
    if (district.status == "good") {
      className += "text-ratingGood";
    } else if (district.status == "bad") {
      className += "text-ratingBad";
    } else {
      className += "text-ratingNormal";
    }
  }

  className += props.active == id ? " active" : "";

  if (hoveredRegion.value == id || props.active == id) {
    className += " active-path";
  } else if (hoveredRegion.value != null && props.active != id) {
    className += " inactive-path";
  }

  return className.trim();
};

watch(
  () => props.active,
  () => (hoveredRegion.value = null),
  { immediate: true }
);
</script>

